# Product of Array Except Self вҖ” O(1) extra
def productExceptSelf(nums):
    n = len(nums)
    res = [1] * n
    left = 1
    for i in range(n):
        res[i] = left
        left *= nums[i]
    right = 1
    for i in range(n-1, -1, -1):
        res[i] *= right
        right *= nums[i]
    return res

# Top K Frequent вҖ” bucket sort O(n)
def topKFrequent(nums, k):
    count = Counter(nums)
    buckets = [[] for _ in range(len(nums)+1)]
    for val, freq in count.items():
        buckets[freq].append(val)
    res = []
    for i in range(len(buckets)-1, -1, -1):
        res.extend(buckets[i])
        if len(res) >= k: break
    return res[:k]

# Valid Parentheses
def isValid(s):
    stack = []
    match = {')': '(', ']': '[', '}': '{'}
    for c in s:
        if c in '([{':
            stack.append(c)
        elif not stack or stack[-1] != match[c]:
            return False
        else:
            stack.pop()
    return not stack

# Next Greater Element вҖ” monotonic decreasing stack
def nextGreaterElements(nums):
    n = len(nums)
    res = [-1] * n
    stack = []  # indices
    for i in range(2 * n):  # circular: mod n
        while stack and nums[stack[-1]] < nums[i % n]:
            res[stack.pop()] = nums[i % n]
        if i < n:
            stack.append(i)
    return res

# Daily Temperatures
def dailyTemperatures(temps):
    res = [0] * len(temps)
    stack = []  # indices of 'waiting' days
    for i, t in enumerate(temps):
        while stack and temps[stack[-1]] < t:
            j = stack.pop()
            res[j] = i - j
        stack.append(i)
    return res

# Largest Rectangle in Histogram
def largestRectangleArea(heights):
    stack = []  # (index, height)
    max_area = 0
    for i, h in enumerate(heights):
        start = i
        while stack and stack[-1][1] > h:
            idx, ht = stack.pop()
            max_area = max(max_area, ht * (i - idx))
            start = idx
        stack.append((start, h))
    for idx, ht in stack:
        max_area = max(max_area, ht * (len(heights) - idx))
    return max_area

