# Find Median from Data Stream вҖ” two heaps
class MedianFinder:
    def __init__(self):
        self.lo = []  # max-heap (negated): stores smaller half
        self.hi = []  # min-heap: stores larger half

    def addNum(self, num):
        heapq.heappush(self.lo, -num)
        # ensure lo.max <= hi.min
        if self.hi and -self.lo[0] > self.hi[0]:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))
        # balance sizes (lo can have 1 more)
        if len(self.lo) > len(self.hi) + 1:
            heapq.heappush(self.hi, -heapq.heappop(self.lo))
        if len(self.hi) > len(self.lo):
            heapq.heappush(self.lo, -heapq.heappop(self.hi))

    def findMedian(self):
        if len(self.lo) > len(self.hi): return -self.lo[0]
        return (-self.lo[0] + self.hi[0]) / 2

# Merge K Sorted Lists
def mergeKLists(lists):
    h = []
    for i, node in enumerate(lists):
        if node: heapq.heappush(h, (node.val, i, node))
    dummy = cur = ListNode()
    while h:
        val, i, node = heapq.heappop(h)
        cur.next = node; cur = cur.next
        if node.next:
            heapq.heappush(h, (node.next.val, i, node.next))
    return dummy.next

# K Closest Points to Origin
def kClosest(points, k):
    # max-heap size k: store (-dist, point)
    h = []
    for x, y in points:
        d = x*x + y*y
        heapq.heappush(h, (-d, x, y))
        if len(h) > k: heapq.heappop(h)
    return [[x, y] for _, x, y in h]

# Subsets
def subsets(nums):
    res = []
    def bt(start, path):
        res.append(path[:])  # snapshot at every node
        for i in range(start, len(nums)):
            path.append(nums[i])
            bt(i+1, path)
            path.pop()
    bt(0, []); return res

# Subsets II вҖ” with duplicates
def subsetsWithDup(nums):
    nums.sort()
    res = []
    def bt(start, path):
        res.append(path[:])
        for i in range(start, len(nums)):
            if i > start and nums[i] == nums[i-1]: continue  # skip dup
            path.append(nums[i]); bt(i+1, path); path.pop()
    bt(0, []); return res

# Combination Sum вҖ” reuse elements allowed
def combinationSum(candidates, target):
    res = []
    def bt(start, path, remaining):
        if remaining == 0: res.append(path[:]); return
        if remaining < 0: return
        for i in range(start, len(candidates)):
            path.append(candidates[i])
            bt(i, path, remaining - candidates[i])  # i not i+1 (reuse)
            path.pop()
    bt(0, [], target); return res

# Permutations
def permute(nums):
    res = []; used = [False] * len(nums)
    def bt(path):
        if len(path) == len(nums): res.append(path[:]); return
        for i, x in enumerate(nums):
            if not used[i]:
                used[i] = True; path.append(x)
                bt(path)
                path.pop(); used[i] = False
    bt([]); return res

# N-Queens вҖ” O(1) validity with sets
def solveNQueens(n):
    cols = set(); pos_diag = set(); neg_diag = set()
    res = []; board = [['.']*n for _ in range(n)]
    def bt(row):
        if row == n:
            res.append([''.join(r) for r in board]); return
        for c in range(n):
            if c in cols or (row+c) in pos_diag or (row-c) in neg_diag:
                continue
            cols.add(c); pos_diag.add(row+c); neg_diag.add(row-c)
            board[row][c] = 'Q'
            bt(row+1)
            board[row][c] = '.'
            cols.discard(c); pos_diag.discard(row+c); neg_diag.discard(row-c)
    bt(0); return res

# Word Search вҖ” DFS + backtrack on grid
def exist(board, word):
    ROWS, COLS = len(board), len(board[0])
    def dfs(r, c, i):
        if i == len(word): return True
        if r<0 or c<0 or r>=ROWS or c>=COLS or board[r][c]!=word[i]: return False
        board[r][c] = '#'  # mark
        found = any(dfs(r+dr, c+dc, i+1) for dr,dc in [(0,1),(0,-1),(1,0),(-1,0)])
        board[r][c] = word[i]  # restore
        return found
    return any(dfs(r,c,0) for r in range(ROWS) for c in range(COLS))

from collections import defaultdict, deque

# BFS вҖ” Shortest Path (unweighted)
def bfs(graph, start, end):
    q = deque([(start, 0)])
    visited = {start}
    while q:
        node, dist = q.popleft()
        if node == end: return dist
        for nei in graph[node]:
            if nei not in visited:
                visited.add(nei)
                q.append((nei, dist+1))
    return -1

# Number of Islands вҖ” DFS on grid
def numIslands(grid):
    ROWS, COLS = len(grid), len(grid[0])
    count = 0
    def dfs(r, c):
        if r<0 or c<0 or r>=ROWS or c>=COLS or grid[r][c]!='1': return
        grid[r][c] = '0'  # mark visited
        for dr,dc in [(0,1),(0,-1),(1,0),(-1,0)]: dfs(r+dr, c+dc)
    for r in range(ROWS):
        for c in range(COLS):
            if grid[r][c] == '1': dfs(r,c); count+=1
    return count

# Topological Sort вҖ” Kahn's Algorithm
def topoSort(n, edges):
    indeg = [0]*n
    adj = defaultdict(list)
    for u,v in edges:
        adj[u].append(v); indeg[v] += 1
    q = deque(i for i in range(n) if indeg[i]==0)
    order = []
    while q:
        u = q.popleft(); order.append(u)
        for v in adj[u]:
            indeg[v] -= 1
            if indeg[v] == 0: q.append(v)
    return order if len(order)==n else []  # [] = cycle exists

# Union-Find with Path Compression + Union by Rank
class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0]*n
        self.components = n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # path compression
        return self.parent[x]

    def union(self, x, y):
        px, py = self.find(x), self.find(y)
        if px == py: return False  # already connected
        if self.rank[px] < self.rank[py]: px, py = py, px
        self.parent[py] = px
        if self.rank[px] == self.rank[py]: self.rank[px] += 1
        self.components -= 1
        return True

# Course Schedule вҖ” cycle detection in directed graph
def canFinish(numCourses, prerequisites):
    adj = defaultdict(list)
    for a,b in prerequisites: adj[b].append(a)
    # 0=unvisited, 1=in-progress, 2=done
    state = [0]*numCourses
    def dfs(u):
        if state[u] == 1: return False  # cycle!
        if state[u] == 2: return True
        state[u] = 1
        for v in adj[u]:
            if not dfs(v): return False
        state[u] = 2; return True
    return all(dfs(i) for i in range(numCourses))

# Pacific Atlantic Water Flow вҖ” BFS from both oceans
def pacificAtlantic(heights):
    ROWS, COLS = len(heights), len(heights[0])
    def bfs(starts):
        q = deque(starts)
        visited = set(starts)
        while q:
            r,c = q.popleft()
            for dr,dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                nr,nc = r+dr, c+dc
                if 0<=nr<ROWS and 0<=nc<COLS and (nr,nc) not in visited:
                    if heights[nr][nc] >= heights[r][c]:
                        visited.add((nr,nc)); q.append((nr,nc))
        return visited
    pac = bfs([(r,0) for r in range(ROWS)] + [(0,c) for c in range(COLS)])
    atl = bfs([(r,COLS-1) for r in range(ROWS)] + [(ROWS-1,c) for c in range(COLS)])
    return [list(p) for p in pac & atl]

# Climbing Stairs вҖ” O(1) space
def climbStairs(n):
    a, b = 1, 1
    for _ in range(n-1): a, b = b, a+b
    return b

# House Robber вҖ” O(1) space
def rob(nums):
    prev2, prev1 = 0, 0
    for x in nums:
        prev2, prev1 = prev1, max(prev1, prev2+x)
    return prev1

# House Robber II (circular) вҖ” run rob on [0..n-2] and [1..n-1]
def robII(nums):
    if len(nums) == 1: return nums[0]
    return max(rob(nums[:-1]), rob(nums[1:]))

# Kadane's Algorithm вҖ” Maximum Subarray
def maxSubArray(nums):
    cur = best = nums[0]
    for x in nums[1:]:
        cur = max(x, cur+x)
        best = max(best, cur)
    return best

# Coin Change вҖ” minimum coins
def coinChange(coins, amount):
    dp = [float('inf')] * (amount+1)
    dp[0] = 0
    for i in range(1, amount+1):
        for c in coins:
            if c <= i:
                dp[i] = min(dp[i], dp[i-c]+1)
    return dp[amount] if dp[amount] != float('inf') else -1

# Longest Increasing Subsequence вҖ” O(nВІ)
def lengthOfLIS(nums):
    n = len(nums)
    dp = [1]*n
    for i in range(1,n):
        for j in range(i):
            if nums[j] < nums[i]:
                dp[i] = max(dp[i], dp[j]+1)
    return max(dp)

# LIS вҖ” O(n log n) with patience sorting
import bisect
def lisNlogN(nums):
    tails = []  # tails[i] = smallest tail of IS with length i+1
    for x in nums:
        pos = bisect.bisect_left(tails, x)
        if pos == len(tails): tails.append(x)
        else: tails[pos] = x
    return len(tails)

# Word Break
def wordBreak(s, wordDict):
    words = set(wordDict)
    n = len(s)
    dp = [False]*(n+1); dp[0] = True
    for i in range(1, n+1):
        for j in range(i):
            if dp[j] and s[j:i] in words:
                dp[i] = True; break
    return dp[n]

# Decode Ways
def numDecodings(s):
    dp = [0]*(len(s)+1)
    dp[0] = 1
    dp[1] = 0 if s[0]=='0' else 1
    for i in range(2, len(s)+1):
        one = int(s[i-1:i])
        two = int(s[i-2:i])
        if 1 <= one <= 9: dp[i] += dp[i-1]
        if 10 <= two <= 26: dp[i] += dp[i-2]
    return dp[-1]

# Longest Common Subsequence
def longestCommonSubsequence(text1, text2):
    m, n = len(text1), len(text2)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if text1[i-1] == text2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

# Edit Distance (Levenshtein)
def minDistance(word1, word2):
    m, n = len(word1), len(word2)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1): dp[i][0] = i  # delete all
    for j in range(n+1): dp[0][j] = j  # insert all
    for i in range(1, m+1):
        for j in range(1, n+1):
            if word1[i-1] == word2[j-1]:
                dp[i][j] = dp[i-1][j-1]  # no op
            else:
                dp[i][j] = 1 + min(
                    dp[i-1][j],    # delete from word1
                    dp[i][j-1],    # insert into word1
                    dp[i-1][j-1]   # replace
                )
    return dp[m][n]

# 0/1 Knapsack
def knapsack01(weights, values, W):
    n = len(weights)
    # Space optimized: single 1D array, iterate W backwards
    dp = [0]*(W+1)
    for i in range(n):
        for w in range(W, weights[i]-1, -1):  # reverse!
            dp[w] = max(dp[w], dp[w-weights[i]] + values[i])
    return dp[W]

# Coin Change II (ways to make amount) вҖ” Unbounded Knapsack
def change(amount, coins):
    dp = [0]*(amount+1); dp[0]=1
    for c in coins:
        for i in range(c, amount+1):
            dp[i] += dp[i-c]  # forward! (unbounded)
    return dp[amount]

# Unique Paths
def uniquePaths(m, n):
    dp = [1]*n
    for _ in range(1, m):
        for j in range(1, n):
            dp[j] += dp[j-1]
    return dp[-1]

# Burst Balloons вҖ” Interval DP
def maxCoins(nums):
    nums = [1] + nums + [1]  # add boundary 1s
    n = len(nums)
    dp = [[0]*n for _ in range(n)]
    for length in range(2, n):
        for l in range(0, n-length):
            r = l + length
            for k in range(l+1, r):  # k = last balloon to burst in (l,r)
                dp[l][r] = max(dp[l][r],
                    nums[l]*nums[k]*nums[r] + dp[l][k] + dp[k][r])
    return dp[0][n-1]

